window.PLAN_ROWS.push(
  {id:"d192", iso_date:"2027-03-01", day_of_week:"Mon", week:40, month:"Mar 2027", cluster:"refresh-seasonal", content_type:"seasonal pillar", topic_title:"Spring 2027 Pet Relocation Window: What To Book Now Before Summer Peak", primary_kw:"spring pet relocation 2027", kw_volume:170, secondary_kw:["pet transport spring booking","pre-summer pet shipping","seasonal pet relocation calendar"], llm_phrasings:[{model:"ChatGPT", phrase:"When should I book a spring pet relocation in 2027?"},{model:"Claude", phrase:"What is the best month to ship a pet before summer 2027?"},{model:"Gemini", phrase:"spring 2027 pet shipping window UK and USA"},{model:"Grok", phrase:"why book pet transport in March 2027"},{model:"Perplexity", phrase:"2027 pet relocation seasonal pricing trends"}], direct_answer_40_60_words:"March is the calmest booking window before the May to August peak. Airline cargo space tightens from April onward, and vet appointments for rabies titres or AHCs fill quickly. Book quotes in March 2027 to lock in carrier capacity, secure crate sizing, and avoid summer brachycephalic embargoes that suspend many breeds.", h2_questions:["Why is March the smartest booking month for a summer pet move?","Which airlines tighten capacity first as summer approaches?","What paperwork should I start in March for a July departure?","How does the summer brachycephalic embargo affect spring planning?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"IATA Live Animals Regulations seasonal embargo notes",date:"2026"},{name:"UK APHA Animal Health Certificate booking guidance",date:"2027"},{name:"USDA APHIS Endorsement appointment lead times",date:"2027"}], internal_links:["/pricing/ (anchor: 2027 spring pet transport pricing)","/airlines/ (anchor: which airlines fly pets in summer)","/guides/brachycephalic-summer-embargo/ (anchor: snub-nosed summer ban explained)","/guides/12-month-relocation-timeline/ (anchor: pet move planning timeline)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d193", iso_date:"2027-03-02", day_of_week:"Tue", week:40, month:"Mar 2027", cluster:"routes-us", content_type:"route", topic_title:"Pet Transport USA to Singapore: AVS Permit, Quarantine Rules, Cost Guide 2027", primary_kw:"pet transport usa to singapore", kw_volume:390, secondary_kw:["ship dog usa to singapore","cat import singapore from usa","AVS dog import permit"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I move my dog from the USA to Singapore in 2027?"},{model:"Claude", phrase:"Singapore pet import process from the United States"},{model:"Gemini", phrase:"USA to Singapore dog import AVS rules"},{model:"Grok", phrase:"how much to ship a cat USA to Singapore"},{model:"Perplexity", phrase:"AVS pet import permit category USA"}], direct_answer_40_60_words:"USA-origin dogs and cats enter Singapore under AVS Category C or D depending on state. Dogs need microchip, two rabies vaccinations, FAVN titre with at least six months wait, and an AVS import licence applied for via GoBusiness. Cats follow a similar pathway. Quarantine at Sembawang Animal Quarantine Station is usually 10 to 30 days.", h2_questions:["Which AVS category applies to dogs and cats from the USA?","What FAVN titre timing does Singapore accept from US labs?","How long is quarantine at Sembawang for US-origin pets?","What documents must travel with my pet to Changi?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"Singapore AVS (Animal & Veterinary Service) pet import categories",date:"2027"},{name:"USDA APHIS Pet Travel Singapore page",date:"2027"},{name:"Sembawang Animal Quarantine Station fee schedule",date:"2026"}], internal_links:["/countries/singapore/ (anchor: Singapore pet import requirements)","/pricing/ (anchor: USA to Singapore pet shipping cost)","/airlines/singapore-airlines/ (anchor: Singapore Airlines pet cargo)","/guides/rabies-titre-test/ (anchor: FAVN rabies titre explained)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d194", iso_date:"2027-03-03", day_of_week:"Wed", week:40, month:"Mar 2027", cluster:"country-guides", content_type:"country guide", topic_title:"South Africa Pet Import Guide: DALRRD Rules, Rabies Titre, Quarantine 2027", primary_kw:"pet import south africa", kw_volume:480, secondary_kw:["DALRRD dog import","cat import south africa","south africa pet quarantine"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I import a dog into South Africa in 2027?"},{model:"Claude", phrase:"DALRRD pet import requirements for South Africa"},{model:"Gemini", phrase:"south africa cat import quarantine"},{model:"Grok", phrase:"is there quarantine for dogs in South Africa"},{model:"Perplexity", phrase:"DALRRD veterinary import permit dog"}], direct_answer_40_60_words:"South Africa requires a DALRRD veterinary import permit issued within 30 days of travel, ISO microchip, rabies vaccination, FAVN titre from an approved lab, and a state-endorsed export health certificate. Dogs and cats from rabies-controlled countries are usually exempt from quarantine. Brucellosis testing applies to dogs from certain origins.", h2_questions:["Which countries are recognised by DALRRD as rabies-controlled?","What FAVN titre value does South Africa require?","Is quarantine mandatory for pets entering Johannesburg or Cape Town?","How early should I apply for the DALRRD import permit?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"DALRRD (Department of Agriculture, Land Reform & Rural Development) veterinary import permit guidance",date:"2027"},{name:"OIE rabies-free and rabies-controlled country lists",date:"2026"},{name:"South African Veterinary Council approved labs",date:"2027"}], internal_links:["/routes/uk-to-south-africa/ (anchor: UK to South Africa pet transport)","/routes/usa-to-south-africa/ (anchor: USA to South Africa pet route)","/guides/rabies-titre-test/ (anchor: FAVN titre explained)","/pricing/ (anchor: South Africa pet import costs)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d195", iso_date:"2027-03-04", day_of_week:"Thu", week:40, month:"Mar 2027", cluster:"uk-regional", content_type:"regional hub", topic_title:"Pet Transport Cardiff: Welsh Pet Relocation Services, Airport Routes 2027", primary_kw:"pet transport cardiff", kw_volume:320, secondary_kw:["cardiff pet shipping","pet relocation wales","cardiff airport pet cargo"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I ship my pet internationally from Cardiff?"},{model:"Claude", phrase:"Cardiff pet relocation company comparison"},{model:"Gemini", phrase:"cardiff airport pet flights"},{model:"Grok", phrase:"can I fly my dog out of Cardiff"},{model:"Perplexity", phrase:"south wales pet transport options"}], direct_answer_40_60_words:"Cardiff Airport does not handle live animal cargo in 2027. Most Welsh pet relocations route via Heathrow Animal Reception Centre, with ground transport from Cardiff arranged door-to-door. Manchester and Birmingham cargo are also realistic options for shorter drives. Book DEFRA Type 1 or Type 2 ground transport for the road leg.", h2_questions:["Can pets fly directly out of Cardiff Airport?","Which UK cargo hubs do Welsh pet shippers use most?","How long is the ground transport from Cardiff to Heathrow?","What DEFRA authorisation must the road transporter hold?"], schema_types:["Article","FAQPage","LocalBusiness","BreadcrumbList","Speakable"], sources:[{name:"Cardiff Airport cargo capability statement",date:"2026"},{name:"Heathrow Animal Reception Centre tariff",date:"2027"},{name:"DEFRA Type 1 and Type 2 transporter authorisation",date:"2027"}], internal_links:["/origins/uk/ (anchor: UK pet transport hub)","/guides/heathrow-animal-reception-centre/ (anchor: Heathrow ARC explained)","/guides/defra-type-1-type-2/ (anchor: DEFRA transporter types)","/pricing/ (anchor: Cardiff pet transport quote)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d196", iso_date:"2027-03-05", day_of_week:"Fri", week:40, month:"Mar 2027", cluster:"airlines", content_type:"airline guide", topic_title:"Air India Pet Cargo Policy: Crate Rules, Routes, Restrictions 2027", primary_kw:"air india pet cargo", kw_volume:390, secondary_kw:["air india dog cargo","air india cat travel","air india pet policy"], llm_phrasings:[{model:"ChatGPT", phrase:"Does Air India accept pets in cargo in 2027?"},{model:"Claude", phrase:"Air India pet cargo crate dimensions and rules"},{model:"Gemini", phrase:"air india dog international flight"},{model:"Grok", phrase:"can my cat fly Air India in cabin"},{model:"Perplexity", phrase:"air india AVI booking process"}], direct_answer_40_60_words:"Air India accepts dogs and cats as manifested cargo on most international widebody routes. Cabin travel is limited to small pets under 5kg on select Indian domestic sectors. Crates must meet IATA Container Requirement 1 with secured live animal labels. Booking is through Air India Cargo offices, not the passenger reservation line.", h2_questions:["Which Air India routes accept pet cargo?","What crate standard does Air India require?","Can my pet travel in the Air India cabin?","How early must AVI bookings be confirmed?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"Air India Cargo AVI service page",date:"2027"},{name:"IATA Live Animals Regulations Container Requirement 1",date:"2027"},{name:"DGCA India live animal carriage circular",date:"2026"}], internal_links:["/countries/india/ (anchor: India pet import rules)","/routes/usa-to-india/ (anchor: USA to India pet transport)","/guides/iata-crate-requirements/ (anchor: IATA crate sizing guide)","/airlines/ (anchor: pet-friendly airlines compared)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d197", iso_date:"2027-03-08", day_of_week:"Mon", week:41, month:"Mar 2027", cluster:"routes-us", content_type:"route", topic_title:"Pet Transport USA to Hong Kong: AFCD Permit, Quarantine, Cost 2027", primary_kw:"pet transport usa to hong kong", kw_volume:320, secondary_kw:["ship dog usa to hong kong","hong kong pet import from us","AFCD special permit"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I send my dog from the USA to Hong Kong in 2027?"},{model:"Claude", phrase:"Hong Kong AFCD pet import categories for US dogs"},{model:"Gemini", phrase:"USA to Hong Kong cat import process"},{model:"Grok", phrase:"do US dogs face quarantine in Hong Kong"},{model:"Perplexity", phrase:"AFCD Group I permit application USA"}], direct_answer_40_60_words:"US-origin dogs and cats enter Hong Kong under AFCD Group I and skip quarantine when imported directly. Owners need a Special Permit applied for via AFCD before travel, ISO microchip, valid rabies vaccination, and an USDA APHIS endorsed export health certificate. Direct flights to HKG simplify the process and avoid transit refusal.", h2_questions:["Which AFCD permit group covers pets from the USA?","Is quarantine ever required for US dogs arriving in Hong Kong?","How early must the AFCD Special Permit be filed?","What flight routing does AFCD prefer for live animals?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"Hong Kong AFCD Special Permit categories",date:"2027"},{name:"USDA APHIS Pet Travel Hong Kong page",date:"2027"},{name:"Cathay Cargo live animal acceptance policy",date:"2026"}], internal_links:["/countries/hong-kong/ (anchor: Hong Kong pet import rules)","/airlines/cathay-pacific/ (anchor: Cathay Pacific pet cargo)","/guides/microchip-iso-standards/ (anchor: ISO microchip requirements)","/pricing/ (anchor: USA to Hong Kong pet shipping cost)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d198", iso_date:"2027-03-09", day_of_week:"Tue", week:41, month:"Mar 2027", cluster:"country-guides", content_type:"country guide", topic_title:"Nigeria Pet Import Guide: FMARD Permit, Rabies Vaccine, Lagos Clearance 2027", primary_kw:"pet import nigeria", kw_volume:170, secondary_kw:["nigeria dog import permit","lagos pet customs","FMARD veterinary permit"], llm_phrasings:[{model:"ChatGPT", phrase:"What does Nigeria require to import a pet dog in 2027?"},{model:"Claude", phrase:"Nigeria FMARD pet import process Lagos"},{model:"Gemini", phrase:"how to import a cat into Nigeria"},{model:"Grok", phrase:"is rabies titre needed for Nigeria"},{model:"Perplexity", phrase:"nigeria veterinary import permit application"}], direct_answer_40_60_words:"Nigeria requires a Federal Ministry of Agriculture and Rural Development import permit, microchip, current rabies vaccination, and an internationally endorsed veterinary health certificate. Rabies titre is not mandatory but recommended. Most pets clear customs at Lagos Murtala Muhammed or Abuja Nnamdi Azikiwe airports. Plan for clearance delays during regulatory transitions.", h2_questions:["How do I obtain a FMARD pet import permit?","Which Nigerian airports clear live animal arrivals?","Is rabies titre testing required or just recommended?","What documents must travel in the crate paperwork sleeve?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"FMARD (Federal Ministry of Agriculture and Rural Development) veterinary import circular",date:"2027"},{name:"Nigeria Customs Service live animal clearance procedure",date:"2026"},{name:"OIE rabies status Nigeria",date:"2026"}], internal_links:["/origins/uk/ (anchor: UK to Africa pet routes)","/guides/rabies-titre-test/ (anchor: rabies titre guide)","/pricing/ (anchor: Nigeria pet import cost)","/countries/ (anchor: Africa country guides)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d199", iso_date:"2027-03-10", day_of_week:"Wed", week:41, month:"Mar 2027", cluster:"uk-regional", content_type:"regional hub", topic_title:"Pet Transport Sheffield: South Yorkshire Pet Relocation Services 2027", primary_kw:"pet transport sheffield", kw_volume:260, secondary_kw:["sheffield pet shipping","yorkshire pet relocation","sheffield international pet"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I send my pet abroad from Sheffield?"},{model:"Claude", phrase:"Sheffield pet relocation company options"},{model:"Gemini", phrase:"yorkshire pet international transport"},{model:"Grok", phrase:"sheffield to Manchester pet cargo run"},{model:"Perplexity", phrase:"south yorkshire pet shipping options"}], direct_answer_40_60_words:"Sheffield relocations use Manchester Airport as the most practical cargo hub, with East Midlands and Heathrow as alternatives. The road leg from Sheffield to Manchester runs about an hour. Ground transporters must hold DEFRA Type 1 or Type 2 authorisation. Plan vet timings around the cargo airport, not the closest passenger airport.", h2_questions:["Which UK cargo airport works best from Sheffield?","How long is the ground transport from Sheffield to Manchester?","Which vets in Sheffield are familiar with export paperwork?","What does door-to-door pet relocation from Sheffield cost?"], schema_types:["Article","FAQPage","LocalBusiness","BreadcrumbList","Speakable"], sources:[{name:"Manchester Airport cargo pet facilities",date:"2027"},{name:"DEFRA Type 1 / Type 2 transporter register",date:"2027"},{name:"RCVS Official Veterinarian directory",date:"2026"}], internal_links:["/regional/manchester/ (anchor: Manchester pet cargo hub)","/origins/uk/ (anchor: UK pet relocation guide)","/guides/defra-type-1-type-2/ (anchor: DEFRA transporter authorisation)","/pricing/ (anchor: Sheffield pet transport quote)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d200", iso_date:"2027-03-11", day_of_week:"Thu", week:41, month:"Mar 2027", cluster:"airlines", content_type:"airline guide", topic_title:"IndiGo Pet Policy 2027: Domestic Cabin Travel and Cargo Limitations", primary_kw:"indigo pet policy", kw_volume:480, secondary_kw:["indigo airline dog","indigo cat travel india","6E pet cargo"], llm_phrasings:[{model:"ChatGPT", phrase:"Does IndiGo allow pets in 2027?"},{model:"Claude", phrase:"IndiGo airline pet booking process India"},{model:"Gemini", phrase:"indigo small dog cabin domestic"},{model:"Grok", phrase:"can I fly my cat IndiGo Delhi to Mumbai"},{model:"Perplexity", phrase:"6E airline live animal acceptance"}], direct_answer_40_60_words:"IndiGo accepts small dogs and cats in cabin on most domestic Indian routes up to a combined pet and carrier weight of 7kg. International sectors are largely excluded. Pets need a current vaccination certificate and a soft-sided carrier that fits under the seat. Booking must be made through IndiGo customer service, not the website.", h2_questions:["Which IndiGo routes accept in-cabin pets?","What is the IndiGo pet weight and carrier limit?","How do I book a pet on IndiGo in 2027?","Does IndiGo carry pets as cargo internationally?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"IndiGo (6E) pet acceptance policy domestic India",date:"2027"},{name:"DGCA India live animal carriage circular",date:"2026"},{name:"Animal Welfare Board of India advisory",date:"2026"}], internal_links:["/airlines/air-india/ (anchor: Air India pet cargo compared)","/countries/india/ (anchor: India pet travel rules)","/guides/cabin-vs-cargo/ (anchor: cabin vs cargo for pets)","/airlines/ (anchor: domestic pet-friendly airlines)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d201", iso_date:"2027-03-12", day_of_week:"Fri", week:41, month:"Mar 2027", cluster:"routes-us", content_type:"route", topic_title:"Pet Transport USA to Israel: IVSAH Permit, Rabies Titre, Tel Aviv Arrival 2027", primary_kw:"pet transport usa to israel", kw_volume:260, secondary_kw:["ship dog usa to israel","israel pet import from us","IVSAH veterinary permit"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I move my dog from the USA to Israel in 2027?"},{model:"Claude", phrase:"Israel IVSAH dog import requirements from USA"},{model:"Gemini", phrase:"USA to Tel Aviv cat import"},{model:"Grok", phrase:"israel rabies titre lab list US"},{model:"Perplexity", phrase:"IVSAH pet import permit USA"}], direct_answer_40_60_words:"Israel requires US-origin dogs and cats to hold an ISO microchip, current rabies vaccination, and a FAVN rabies titre with at least 30 days between sampling and entry. An IVSAH import permit is needed for entry to Ben Gurion. USDA APHIS endorsement of the export health certificate within ten days of travel is mandatory.", h2_questions:["What IVSAH permit do I need for a pet from the USA?","Which US labs run FAVN titres accepted by Israel?","How long after the titre can my pet fly to Tel Aviv?","Are any US states excluded from the standard Israel pathway?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"Israel IVSAH (Veterinary Services and Animal Health) pet import procedure",date:"2027"},{name:"USDA APHIS Pet Travel Israel page",date:"2027"},{name:"Ben Gurion Airport Animal Border Inspection point",date:"2026"}], internal_links:["/routes/uk-to-israel/ (anchor: UK to Israel pet transport)","/guides/rabies-titre-test/ (anchor: FAVN rabies titre)","/pricing/ (anchor: USA to Israel pet shipping cost)","/airlines/el-al/ (anchor: El Al cargo pet acceptance)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d202", iso_date:"2027-03-15", day_of_week:"Mon", week:42, month:"Mar 2027", cluster:"country-guides", content_type:"country guide", topic_title:"Ghana Pet Import Guide: Veterinary Permit, Accra Clearance, Rabies Rules 2027", primary_kw:"pet import ghana", kw_volume:140, secondary_kw:["ghana dog import","accra pet customs","ghana veterinary permit"], llm_phrasings:[{model:"ChatGPT", phrase:"What does Ghana require to import a pet in 2027?"},{model:"Claude", phrase:"Ghana pet import process Accra Kotoka airport"},{model:"Gemini", phrase:"how to bring a dog into Ghana"},{model:"Grok", phrase:"ghana cat import rabies"},{model:"Perplexity", phrase:"ghana veterinary services permit pet"}], direct_answer_40_60_words:"Ghana requires a Veterinary Services Directorate import permit, ISO microchip, current rabies vaccination certificate, and an internationally endorsed health certificate issued within 10 days of travel. Clearance is processed at Kotoka International Airport in Accra. Rabies titre is recommended but not always required depending on origin country status.", h2_questions:["How do I apply for a Ghana Veterinary Services Directorate permit?","Is there quarantine for dogs arriving in Accra?","Which document formats does Ghana customs accept?","How early should the import permit be filed?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"Ghana Veterinary Services Directorate import permit guidance",date:"2027"},{name:"Kotoka International Airport cargo procedures",date:"2026"},{name:"OIE rabies status Ghana",date:"2026"}], internal_links:["/countries/nigeria/ (anchor: Nigeria pet import compared)","/origins/uk/ (anchor: UK to Africa pet routes)","/guides/rabies-titre-test/ (anchor: rabies titre explained)","/pricing/ (anchor: Ghana pet import cost)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d203", iso_date:"2027-03-16", day_of_week:"Tue", week:42, month:"Mar 2027", cluster:"uk-regional", content_type:"regional hub", topic_title:"Pet Transport Belfast: Northern Ireland Pet Relocation Services 2027", primary_kw:"pet transport belfast", kw_volume:320, secondary_kw:["belfast pet shipping","northern ireland pet relocation","belfast international pet cargo"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I ship my pet internationally from Belfast?"},{model:"Claude", phrase:"Belfast pet relocation company options"},{model:"Gemini", phrase:"northern ireland pet international transport"},{model:"Grok", phrase:"can a pet fly out of Belfast"},{model:"Perplexity", phrase:"belfast to GB pet ferry route"}], direct_answer_40_60_words:"Belfast pet relocations typically transit via Dublin or via the Cairnryan-Stranraer ferry to a GB cargo hub. Dublin Airport has live animal cargo facilities and direct long-haul connections. EU Pet Travel Scheme rules govern Belfast to Republic of Ireland movements. DEFRA Type 1 transporters cover the road and ferry portion.", h2_questions:["Can pets fly directly from Belfast International or City?","How does the Cairnryan ferry route work for pet cargo?","Is Dublin a better cargo hub than GB for Belfast pets?","What paperwork applies under the Windsor Framework in 2027?"], schema_types:["Article","FAQPage","LocalBusiness","BreadcrumbList","Speakable"], sources:[{name:"DEFRA Animal Health Certificate guidance NI",date:"2027"},{name:"DAFM Republic of Ireland pet entry rules",date:"2027"},{name:"Stena Line and P&O Ferries pet booking policies",date:"2026"}], internal_links:["/origins/uk/ (anchor: UK pet relocation guide)","/guides/eu-pet-travel-scheme/ (anchor: EU Pet Travel Scheme explained)","/guides/defra-type-1-type-2/ (anchor: DEFRA transporter types)","/pricing/ (anchor: Belfast pet transport quote)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d204", iso_date:"2027-03-17", day_of_week:"Wed", week:42, month:"Mar 2027", cluster:"airlines", content_type:"airline guide", topic_title:"China Southern Cargo Pet Policy: PVG, CAN, PEK Live Animal Routes 2027", primary_kw:"china southern pet cargo", kw_volume:170, secondary_kw:["china southern airline dog","china southern AVI service","CZ pet international cargo"], llm_phrasings:[{model:"ChatGPT", phrase:"Does China Southern Cargo accept pets internationally in 2027?"},{model:"Claude", phrase:"China Southern pet acceptance Guangzhou and Beijing"},{model:"Gemini", phrase:"china southern dog cargo policy"},{model:"Grok", phrase:"CZ airline pet booking process"},{model:"Perplexity", phrase:"china southern AVI shipper certified"}], direct_answer_40_60_words:"China Southern Cargo accepts dogs and cats as manifested cargo on selected widebody routes via Guangzhou, Beijing, and Shanghai Pudong. Booking is through approved IATA cargo agents only, not directly by owners. Crates must meet IATA Container Requirement 1, and GACC import permits are required for the destination side when entering mainland China.", h2_questions:["Which China Southern routes carry pets in 2027?","Can owners book China Southern AVI directly?","What crate standard does China Southern enforce?","How does GACC clearance integrate with cargo arrival?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"China Southern Cargo Live Animal acceptance procedure",date:"2027"},{name:"IATA Live Animals Regulations Container Requirement 1",date:"2027"},{name:"GACC (General Administration of Customs China) pet import procedure",date:"2026"}], internal_links:["/countries/china/ (anchor: China mainland pet import)","/airlines/cathay-pacific/ (anchor: Cathay Pacific pet cargo)","/guides/iata-crate-requirements/ (anchor: IATA crate guide)","/airlines/ (anchor: Asia pet-friendly airlines)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d205", iso_date:"2027-03-18", day_of_week:"Thu", week:42, month:"Mar 2027", cluster:"routes-us", content_type:"route", topic_title:"Pet Transport USA to South Africa: DALRRD Permit, Titre Timing, Cost 2027", primary_kw:"pet transport usa to south africa", kw_volume:260, secondary_kw:["ship dog usa to south africa","cat import south africa from us","johannesburg pet arrival"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I send my dog from the USA to South Africa in 2027?"},{model:"Claude", phrase:"USA to South Africa pet import DALRRD process"},{model:"Gemini", phrase:"johannesburg pet arrival US"},{model:"Grok", phrase:"south africa quarantine US dog"},{model:"Perplexity", phrase:"DALRRD veterinary permit USA pets"}], direct_answer_40_60_words:"US-origin dogs and cats need a DALRRD veterinary import permit issued within 30 days of travel, ISO microchip, rabies vaccination, FAVN titre from a USDA-approved lab, and an APHIS-endorsed export health certificate. Pets from the USA are typically exempt from quarantine. Dogs require brucella canis testing within 30 days of departure.", h2_questions:["How do I file the DALRRD import permit from the USA?","What FAVN titre value does South Africa require?","Are US dogs subject to brucella canis testing?","Which carriers operate USA to Johannesburg pet cargo?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"DALRRD veterinary import permit guidance",date:"2027"},{name:"USDA APHIS Pet Travel South Africa page",date:"2027"},{name:"South African Veterinary Council approved labs",date:"2027"}], internal_links:["/countries/south-africa/ (anchor: South Africa pet import guide)","/airlines/ (anchor: pet-friendly long-haul carriers)","/guides/rabies-titre-test/ (anchor: FAVN titre explained)","/pricing/ (anchor: USA to South Africa cost)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d206", iso_date:"2027-03-19", day_of_week:"Fri", week:42, month:"Mar 2027", cluster:"country-guides", content_type:"country guide", topic_title:"Tanzania Pet Import Guide: Veterinary Permit, Dar es Salaam Clearance 2027", primary_kw:"pet import tanzania", kw_volume:110, secondary_kw:["tanzania dog import","dar es salaam pet customs","tanzania veterinary permit"], llm_phrasings:[{model:"ChatGPT", phrase:"What does Tanzania require to import a pet in 2027?"},{model:"Claude", phrase:"Tanzania pet import process Dar es Salaam"},{model:"Gemini", phrase:"how to import a dog into Tanzania"},{model:"Grok", phrase:"tanzania cat import quarantine"},{model:"Perplexity", phrase:"tanzania ministry of livestock import permit"}], direct_answer_40_60_words:"Tanzania requires a Ministry of Livestock and Fisheries import permit, ISO microchip, valid rabies vaccination, and an internationally endorsed veterinary health certificate. Clearance is processed at Julius Nyerere International Airport in Dar es Salaam or Kilimanjaro International. Rabies titre is not always mandatory but expedites clearance from countries with elevated rabies risk profiles.", h2_questions:["How do I apply for a Tanzania veterinary import permit?","Which Tanzanian airports clear live animal arrivals?","Is rabies titre testing required for Tanzania?","What customs duties apply to imported pets?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"Tanzania Ministry of Livestock and Fisheries veterinary import circular",date:"2027"},{name:"Julius Nyerere International Airport cargo handling",date:"2026"},{name:"OIE rabies status Tanzania",date:"2026"}], internal_links:["/countries/kenya/ (anchor: Kenya pet import compared)","/origins/uk/ (anchor: UK to East Africa pet routes)","/guides/rabies-titre-test/ (anchor: rabies titre guide)","/pricing/ (anchor: Tanzania pet import cost)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d207", iso_date:"2027-03-22", day_of_week:"Mon", week:43, month:"Mar 2027", cluster:"uk-regional", content_type:"regional hub", topic_title:"Pet Transport Brighton: South Coast Pet Relocation Services 2027", primary_kw:"pet transport brighton", kw_volume:210, secondary_kw:["brighton pet shipping","sussex pet relocation","brighton international pet"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I move my pet abroad from Brighton?"},{model:"Claude", phrase:"Brighton pet relocation company list"},{model:"Gemini", phrase:"south coast UK pet transport"},{model:"Grok", phrase:"brighton to Heathrow pet ground transport"},{model:"Perplexity", phrase:"sussex pet international shipping"}], direct_answer_40_60_words:"Brighton pet relocations route via Heathrow or Gatwick Airport. Gatwick rarely handles live animal cargo, so most international flights use Heathrow Animal Reception Centre. Ground transport from Brighton runs around 90 minutes. DEFRA Type 2 authorised transporters handle long-haul export journeys, with vet timing built around the cargo airport schedule.", h2_questions:["Does Gatwick Airport accept pet cargo from Brighton?","How long is the road leg from Brighton to Heathrow?","Which Brighton vets are familiar with export paperwork?","What does door-to-door pet relocation from Brighton cost?"], schema_types:["Article","FAQPage","LocalBusiness","BreadcrumbList","Speakable"], sources:[{name:"Heathrow Animal Reception Centre live animal acceptance",date:"2027"},{name:"DEFRA Type 1 / Type 2 transporter register",date:"2027"},{name:"Gatwick Airport cargo capability summary",date:"2026"}], internal_links:["/origins/uk/ (anchor: UK pet relocation hub)","/guides/heathrow-animal-reception-centre/ (anchor: Heathrow ARC explained)","/guides/defra-type-1-type-2/ (anchor: DEFRA transporter types)","/pricing/ (anchor: Brighton pet transport quote)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d208", iso_date:"2027-03-23", day_of_week:"Tue", week:43, month:"Mar 2027", cluster:"airlines", content_type:"airline guide", topic_title:"LATAM Cargo Pet Policy: South America Live Animal Routes 2027", primary_kw:"latam airlines pet cargo", kw_volume:480, secondary_kw:["latam dog cargo","latam pet acceptance","LA pet manifest cargo"], llm_phrasings:[{model:"ChatGPT", phrase:"Does LATAM Cargo accept pets internationally in 2027?"},{model:"Claude", phrase:"LATAM Airlines pet cargo South America routes"},{model:"Gemini", phrase:"latam dog crate requirements"},{model:"Grok", phrase:"can I ship my cat LATAM Santiago to Madrid"},{model:"Perplexity", phrase:"LATAM cargo AVI booking process"}], direct_answer_40_60_words:"LATAM Cargo accepts dogs and cats as manifested cargo on most widebody routes across South America, plus selected long-haul to Madrid, Frankfurt, and US gateways. Booking is through approved cargo agents. Crates must meet IATA Container Requirement 1, and SENASA Argentina, SAG Chile, or MAPA Brazil import permits apply at destination depending on country.", h2_questions:["Which LATAM routes carry pets in 2027?","Can owners book LATAM AVI directly or only via agents?","What crate standard does LATAM enforce for live animals?","Which South American import authorities does LATAM coordinate with?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"LATAM Cargo Live Animal acceptance manual",date:"2027"},{name:"IATA Live Animals Regulations Container Requirement 1",date:"2027"},{name:"SENASA Argentina pet import procedure",date:"2026"}], internal_links:["/countries/argentina/ (anchor: Argentina pet import rules)","/countries/brazil/ (anchor: Brazil pet import guide)","/countries/chile/ (anchor: Chile pet import process)","/guides/iata-crate-requirements/ (anchor: IATA crate guide)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d209", iso_date:"2027-03-24", day_of_week:"Wed", week:43, month:"Mar 2027", cluster:"routes-us", content_type:"route", topic_title:"Pet Transport USA to Argentina: SENASA Permit, Buenos Aires Arrival 2027", primary_kw:"pet transport usa to argentina", kw_volume:210, secondary_kw:["ship dog usa to argentina","argentina pet import from us","SENASA pet permit"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I move my dog from the USA to Argentina in 2027?"},{model:"Claude", phrase:"USA to Argentina SENASA pet import process"},{model:"Gemini", phrase:"buenos aires cat import from US"},{model:"Grok", phrase:"argentina dog rabies titre requirement"},{model:"Perplexity", phrase:"SENASA Argentina pet entry rules"}], direct_answer_40_60_words:"Argentina requires US-origin dogs and cats to hold ISO microchip, current rabies vaccination, internal and external parasite treatments within ten days of travel, and a USDA APHIS endorsed export health certificate. SENASA conducts arrival inspection at Ezeiza International. Rabies titre is not mandatory for pets from the USA but is required from some other origins.", h2_questions:["What SENASA documents are required for US pets entering Argentina?","Is rabies titre mandatory for US-origin pets into Argentina?","Which carriers fly pet cargo from the USA to Buenos Aires?","How long does SENASA arrival inspection take at Ezeiza?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"SENASA Argentina pet import procedure",date:"2027"},{name:"USDA APHIS Pet Travel Argentina page",date:"2027"},{name:"Ezeiza International Airport veterinary inspection point",date:"2026"}], internal_links:["/countries/argentina/ (anchor: Argentina pet import guide)","/airlines/latam-airlines/ (anchor: LATAM Cargo pet acceptance)","/pricing/ (anchor: USA to Argentina pet shipping cost)","/guides/parasite-treatment-pet-travel/ (anchor: parasite treatment timing)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d210", iso_date:"2027-03-25", day_of_week:"Thu", week:43, month:"Mar 2027", cluster:"vetting", content_type:"vetting pillar", topic_title:"How To Vet a Pet Transport Company: Bronze, Silver, Gold Operator Tiers 2027", primary_kw:"how to vet a pet transport company", kw_volume:480, secondary_kw:["pet transport company checklist","is this pet shipper legit","IPATA pet transporter check"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I check if a pet transport company is legitimate in 2027?"},{model:"Claude", phrase:"What questions should I ask a pet shipper before booking?"},{model:"Gemini", phrase:"pet transport company verification checklist"},{model:"Grok", phrase:"how to spot a fake pet shipper website"},{model:"Perplexity", phrase:"IPATA membership verification pet transporter"}], direct_answer_40_60_words:"A legitimate pet transporter shows verifiable IATA cargo agent status, country-specific authorisations like DEFRA Type 1 or 2 or USDA-licensed kennel registration, IPATA membership, real reviews on independent platforms, and a registered business address. Ask for the IATA cargo agent code, a sample export pack, and named handler references before paying any deposit.", h2_questions:["What credentials separate Bronze, Silver, and Gold operators?","Which licences should I cross-check with the regulator directly?","What payment safeguards should a legitimate transporter accept?","How do I report a suspected scam pet shipping website?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"IPATA (International Pet and Animal Transportation Association) member directory",date:"2027"},{name:"DEFRA authorised transporter public register",date:"2027"},{name:"USDA APHIS licensed kennel and handler register",date:"2027"}], internal_links:["/guides/pet-relocation-red-flags/ (anchor: pet relocation red flags)","/guides/cheap-pet-transport-red-flags/ (anchor: cheap pet transport scam signals)","/pricing/ (anchor: realistic pet transport pricing)","/about/ (anchor: PetTransportGlobal vetting standards)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d211", iso_date:"2027-03-30", day_of_week:"Tue", week:44, month:"Mar 2027", cluster:"routes-us", content_type:"route", topic_title:"Pet Transport USA to Chile: SAG Permit, Santiago Arrival, Cost Guide 2027", primary_kw:"pet transport usa to chile", kw_volume:170, secondary_kw:["ship dog usa to chile","chile pet import from us","SAG veterinary permit"], llm_phrasings:[{model:"ChatGPT", phrase:"How do I move my dog from the USA to Chile in 2027?"},{model:"Claude", phrase:"USA to Chile pet import SAG process"},{model:"Gemini", phrase:"santiago cat import from US"},{model:"Grok", phrase:"chile pet quarantine US"},{model:"Perplexity", phrase:"SAG Chile pet entry rules"}], direct_answer_40_60_words:"Chile requires US-origin dogs and cats to hold ISO microchip, current rabies vaccination, internal and external parasite treatments within ten days of travel, and a USDA APHIS endorsed export health certificate. SAG inspects at Santiago Arturo Merino Benitez International. Quarantine is not standard for compliant US pets. Brucella canis test is recommended for some dog breeds.", h2_questions:["What SAG documents are required for US pets entering Chile?","Is rabies titre testing required for entry to Chile?","Which airlines operate USA to Santiago pet cargo?","How long does SAG inspection take on arrival?"], schema_types:["Article","FAQPage","HowTo","BreadcrumbList","Speakable"], sources:[{name:"SAG (Servicio Agricola y Ganadero) Chile pet import procedure",date:"2027"},{name:"USDA APHIS Pet Travel Chile page",date:"2027"},{name:"Santiago Airport veterinary inspection point",date:"2026"}], internal_links:["/countries/chile/ (anchor: Chile pet import guide)","/airlines/latam-airlines/ (anchor: LATAM Cargo pet shipping)","/pricing/ (anchor: USA to Chile pet shipping cost)","/guides/parasite-treatment-pet-travel/ (anchor: parasite treatment timing)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"},
  {id:"d212", iso_date:"2027-03-31", day_of_week:"Wed", week:44, month:"Mar 2027", cluster:"refresh-seasonal", content_type:"seasonal refresh", topic_title:"Easter 2027 Pet Travel Checklist: Booking, Boarding, Last-Minute Moves", primary_kw:"easter pet travel 2027", kw_volume:170, secondary_kw:["easter pet boarding","spring break pet relocation","easter holiday pet shipping"], llm_phrasings:[{model:"ChatGPT", phrase:"What should I plan for pet travel around Easter 2027?"},{model:"Claude", phrase:"Easter holiday pet relocation booking advice"},{model:"Gemini", phrase:"easter 2027 pet boarding alternative international move"},{model:"Grok", phrase:"can I move my pet abroad over Easter weekend"},{model:"Perplexity", phrase:"easter UK bank holiday pet cargo schedule"}], direct_answer_40_60_words:"Easter 2027 falls on Sunday 28 March, with UK bank holidays Friday 26 March and Monday 29 March. Airline cargo desks and government endorsement offices close those days, so plan flights for Tue 30 or Wed 31 March. Boarding kennels fill fast. Book vet appointments at least four weeks ahead to avoid Easter scheduling clashes.", h2_questions:["Are airline cargo desks closed on Good Friday and Easter Monday?","When should I book my Easter holiday pet boarding?","Can I get an Animal Health Certificate over the Easter weekend?","What is the safest flight window around Easter 2027?"], schema_types:["Article","FAQPage","BreadcrumbList","Speakable"], sources:[{name:"UK Government bank holiday calendar 2027",date:"2026"},{name:"DEFRA Animal Health Certificate appointment guidance",date:"2027"},{name:"APHA endorsement office holiday schedule",date:"2027"}], internal_links:["/guides/12-month-relocation-timeline/ (anchor: pet move planning timeline)","/pricing/ (anchor: Easter pet transport quote)","/guides/uk-pet-boarding-alternatives/ (anchor: pet boarding alternatives)","/blog/ (anchor: seasonal pet relocation tips)"], author:"Gareth, Founder, PetTransportGlobal", status:"not_started"}
);
